set click_least_once = 1
where seq = #{seq}

UPDATE TB_CS_TRANSCRIPTION
set train_text = null
where seq = #{seq}

UPDATE TB_CS_TRANSCRIPTION
set use_yn = #{useYn}

	, data_id = #{dataId}


	, train_text = stt_text


	, error_msg = #{errorMsg}

where seq = #{seq}

UPDATE TB_CS_TRANSCRIPTION set
	end = #{end}
	, stt_text = #{sttText}
	, train_text = NULL
	, error_msg = NULL
where seq = #{seq}

