    	insert into TB_CS_TRANS_PAIR (
    		data_id
    		, seq
    		, train_text
    		, use_yn
    		, start
    		, end
    	) values (
    		#{dataId}
    		, #{seq}
    		, #{trainText}
    		, #{useYn}
    		, #{start}
    		, #{end}
    	)  
    	on duplicate key update
		    seq = #{seq}
			, train_text = #{trainText}
			, use_yn = #{useYn}
			, start = #{start}
			, end = #{end}

mapper.select:
SELECT tr.SEQ as seq, ROUND(tr.start, 2) AS start, ROUND(tr.end, 2) AS end, tr.reliability, tr.stt_text AS sttText, tr.train_text AS trainText, tr.data_id AS dataId, kw.tts_text AS TtsText, kw.tts_pronounce AS TtsPronText, kw.keyword_text AS keywordText, kw.file_new_nm AS newnm, kw.SEQ as keywordSeq, ( SELECT count(tra.SEQ) from TB_CS_TRANSCRIPTION tra JOIN TB_CS_TTS_KEYWORD kwa ON kwa.SEQ = tra.tts_seq JOIN TB_CS_TTS soa ON soa.SEQ = kwa.tts_seq WHERE soa.SEQ = #{seq}
and tra.reliability <= #{reliability}
) AS hiddenCount FROM TB_CS_TRANSCRIPTION tr JOIN TB_CS_TTS_KEYWORD kw ON kw.SEQ = tr.tts_seq JOIN TB_CS_TTS so ON so.SEQ = kw.tts_seq WHERE so.SEQ = #{seq}
and tr.reliability <= #{reliability}
ORDER BY kw.SEQ
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

